var p=msg.payload;
if(!p||p.capteur===undefined||p.valeur===undefined)return null;
msg.payload=[[{measurement:'machine_data',fields:{valeur:parseFloat(p.valeur)||0,seuil:parseFloat(p.seuil)||0,derive:parseFloat(p.derive)||0,anomalie:p.anomalie?1:0},tags:{zone:String(p.zone||'unknown'),machine:String(p.machine||'unknown'),capteur:String(p.capteur||'unknown'),unite:String(p.unite||'')},timestamp:new Date(p.timestamp||Date.now()).getTime()*1000000}]];
msg.org='industritech';
msg.bucket='iot_data';
msg.precision='ns';
return msg;

var p=msg.payload;
var s={topic:'factory/'+p.zone+'/'+p.machine+'/commande',payload:JSON.stringify({commande:'STOP',raison:'Vibration critique: '+p.valeur+' mm/s',timestamp:new Date().toISOString()})};
node.warn('🚨 ARRÊT AUTO: '+p.machine+' | vib='+p.valeur+' mm/s');
return[s,{payload:'🚨 ARRÊT AUTO\nMachine: '+p.machine+'\nVibration: '+p.valeur+' mm/s (seuil 8.0)\n'+p.timestamp}];

var p=msg.payload;
msg.payload='⚠️ ALERTE Vibration
Machine: '+p.machine+' | Zone: '+p.zone+'
Valeur: '+p.valeur+' mm/s (seuil 5.0)
'+p.timestamp;
return msg;

var p=msg.payload;
msg.payload='🔥 TEMPÉRATURE CRITIQUE
Machine: '+p.machine+' | Zone: '+p.zone+'
Valeur: '+p.valeur+'°C (seuil 80)
'+p.timestamp;
