var p=msg.payload;
msg.payload='⚡ Avert. Temp
Machine: '+p.machine+' | Zone: '+p.zone+'
Valeur: '+p.valeur+'°C
'+p.timestamp;
return msg;

var p=msg.payload;
msg.payload='💡 ANOMALIE Luminosité
Local: '+p.zone+'
Valeur: '+p.valeur+' lux (seuil < 50)
'+p.timestamp;
return msg;

var message=msg.payload||'';
msg.payload=[[{measurement:'alertes',fields:{message:message.substring(0,255)},tags:{type:'alerte'},timestamp:Date.now()*1000000}]];
msg.org='industritech';
msg.bucket='iot_data';
return msg;

var trend=context.get('trend')||0;
if(Math.random()<0.01){trend+=0.05;context.set('trend',trend);}
var t=Date.now()/1000;
var value=2.0+trend+Math.sin(t*2.5)*0.3+(Math.random()-0.5)*0.3;
value=Math.round(value*1000)/1000;
msg.topic='factory/atelier/presse/vibration';
msg.payload=JSON.stringify({zone:'atelier',machine:'presse',capteur:'vibration',valeur:value,unite:'mm/s',seuil:5.0,anomalie:value>5.0,derive:Math.round(trend*1000)/1000,timestamp:new Date().toISOString()});
return msg;

var trend=context.get('trend')||0;
if(Math.random()<0.015){trend+=0.03;context.set('trend',trend);}
var t=Date.now()/1000;
var value=22.0+trend*1.5+Math.sin(t*0.1)*1.5+(Math.random()-0.5)*0.5;
value=Math.round(value*100)/100;
msg.topic='factory/salle_serveur/rack_principal/temperature';
msg.payload=JSON.stringify({zone:'salle_serveur',machine:'rack_principal',capteur:'temperature',valeur:value,unite:'°C',seuil:28.0,anomalie:value>28.0,derive:Math.round(trend*1000)/1000,timestamp:new Date().toISOString()});
return msg;

var trend=context.get('trend')||0;
if(Math.random()<0.02){trend+=0.5;context.set('trend',trend);}
var t=Date.now()/1000;
var value=Math.max(0,200.0-trend*5+Math.cos(t*0.2)*20+(Math.random()-0.5)*10);
value=Math.round(value*10)/10;
msg.topic='factory/local_elec/armoire_1/luminosite';
msg.payload=JSON.stringify({zone:'local_elec',machine:'armoire_1',capteur:'luminosite',valeur:value,unite:'lux',seuil:50.0,anomalie:value<50.0,derive:Math.round(trend*100)/100,timestamp:new Date().toISOString()});
return msg;

var p = msg.payload;
if(!p || p.capteur === undefined || p.valeur === undefined) return null;
var ts = new Date(p.timestamp || Date.now()).getTime() * 1000000;
function encodeTag(s){ return String(s).replace(/ /g,'\\ ').replace(/,/g,'\\,').replace(/=/g,'\\='); }
var tags = 'machine_data,zone=' + encodeTag(p.zone||'?') + ',machine=' + encodeTag(p.machine||'?') + ',capteur=' + encodeTag(p.capteur||'?') + ',unite=' + encodeTag(p.unite||'none');
var fields = 'valeur=' + parseFloat(p.valeur) + ',seuil=' + parseFloat(p.seuil||0) + ',derive=' + parseFloat(p.derive||0) + ',anomalie=' + (p.anomalie ? '1i' : '0i');
msg.payload = tags + ' ' + fields + ' ' + ts;
msg.headers = {'Content-Type': 'text/plain; charset=utf-8', 'Authorization': 'Token mytoken123superlong'};
return msg;
